(function () {
  const React = window.React;
  const ReactDOM = window.ReactDOM;
  const Modifier = window.DraftJS.Modifier;
  const RichUtils = window.DraftJS.RichUtils;
  const EditorState = window.DraftJS.EditorState;

  console.log("React:", React);
  console.log("ReactDOM:", ReactDOM);

  const style = document.createElement("style");
  style.textContent = `
    .color-picker-modal {
      position: relative;
      pointer-events: auto !important;
      z-index: 9999;
      background: white;
      padding: 1em;
      border: 1px solid #ccc;
      max-width: 300px;
    }
  `;
  document.head.appendChild(style);

  class ColorPickerModal extends React.Component {
    constructor(props) {
      super(props);
      console.log("Color plugin props:", this.props);
      this.state = {
        color: typeof props.entity?.getData?.().color === 'string'
          ? props.entity.getData().color
          : '#ff0000'
      };

    }

    handleChange = (e) => {
      this.setState({ color: e.target.value });
    };

    handleCancel = () => {
      console.log("Cancel clicked");
      if (typeof this.props.onClose === "function") {
        this.props.onClose();
      } else {
        console.warn("onClose is missing!");
      }
    };

    applyColor = () => {
      const { editorState, onComplete } = this.props;
      const { color } = this.state;

      console.log("Applying color", color);

      const selection = editorState.getSelection();
      const contentState = editorState.getCurrentContent();
      const currentStyle = editorState.getCurrentInlineStyle();

      // Step 1: Remove existing COLOR_ styles
      let nextContentState = contentState;
      currentStyle.forEach(style => {
        if (style.startsWith('COLOR_')) {
          nextContentState = Modifier.removeInlineStyle(nextContentState, selection, style);
        }
      });

      // Step 2: Push content state with removed styles (if changed)
      let nextEditorState = EditorState.push(
        editorState,
        nextContentState,
        'change-inline-style'
      );

      // Step 3: Apply the new style
      const newColorStyle = `COLOR_${color}`;
      console.log("newColorStyle =", newColorStyle);

      nextEditorState = RichUtils.toggleInlineStyle(nextEditorState, newColorStyle);

      // Step 4: Ensure selection is maintained and return result
      nextEditorState = EditorState.forceSelection(nextEditorState, selection);

      // Step 5: Finish
      onComplete(nextEditorState);
    };


    render() {
      const { color } = this.state;

      return (
        <>
          <div className="color-picker-modal">
            <label>Select a color:</label>
            <input
              type="color"
              value={color}
              onChange={this.handleChange}
            />
            <div style={{ marginTop: "1em" }}>
              <button type="button" onClick={this.applyColor}>
                Apply
              </button>
              <button type="button" onClick={this.handleCancel}>
                Cancel
              </button>
            </div>
          </div>
        </>
      );
    }

  }

  const colors = ['#FF0000', '#00FF00', '#0000FF', '#FFFF00', '#FF00FF']; // etc.

  const inlineStyles = colors.map(color => ({
    type: `COLOR_${color.toUpperCase()}`,
    style: { color },
  }));

  window.draftail.registerPlugin({
    type: 'CUSTOM_COLOR',
    source: (props) => {
      console.log("register Plugin ", props);
      let jsx = <ColorPickerModal {...props} />;
      return jsx;
    },
    //decorator: ({ children, entity }) => {
    //  const { color } = entity.getData();
    //  return React.createElement("span", { style: { color } }, children);
    //},
    inlineStyles,
  });


})();

